#!/usr/bin/env node
/**
 * Apply the committed `public` schema seed (Better Auth + LangGraph + misc app
 * tables) to the database named by SUPABASE_DB_URL. Used by the RBAC browser
 * e2e CI job to provision a fresh Postgres before the dev server boots — the
 * dev server's instrumentation hook touches `public.user` and fails with
 * `relation "public.user" does not exist` otherwise.
 *
 * The seed is generated by scripts/dump-public-schema.mjs and is fully
 * idempotent (IF NOT EXISTS / guarded DO blocks), so re-applying is safe.
 *
 *   node scripts/apply-public-schema.mjs
 */
import { Client } from "pg";
import { readFileSync } from "node:fs";

const SQL_PATH = "tests/e2e/rbac/fixtures/public-schema.sql";
const DATABASE_URL = process.env.SUPABASE_DB_URL;
if (!DATABASE_URL) {
  console.error("SUPABASE_DB_URL required");
  process.exit(1);
}

const c = new Client({ connectionString: DATABASE_URL });
await c.connect();
await c.query(readFileSync(SQL_PATH, "utf8"));
await c.end();
console.log(`applied ${SQL_PATH}`);
